import * as Keychain from 'react-native-keychain';

const AUTH_TOKEN_SERVICE = 'com.myapp.authtoken';
const REFRESH_TOKEN_SERVICE = 'com.myapp.refreshtoken';

export const SecureStorage = {
  async saveAuthToken(token) {
    try {
      await Keychain.setGenericPassword('authToken', token, {
        service: AUTH_TOKEN_SERVICE,
        accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      });
    } catch (error) {
      console.error('Failed to save auth token securely:', error);
      throw error;
    }
  },

  async getAuthToken() {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: AUTH_TOKEN_SERVICE,
      });
      if (credentials) {
        return credentials.password;
      }
      return null;
    } catch (error) {
      console.error('Failed to retrieve auth token:', error);
      return null;
    }
  },

  async saveRefreshToken(token) {
    try {
      await Keychain.setGenericPassword('refreshToken', token, {
        service: REFRESH_TOKEN_SERVICE,
        accessControl: Keychain.ACCESS_CONTROL.BIOMETRY_ANY_OR_DEVICE_PASSCODE,
        accessible: Keychain.ACCESSIBLE.WHEN_UNLOCKED_THIS_DEVICE_ONLY,
      });
    } catch (error) {
      console.error('Failed to save refresh token securely:', error);
      throw error;
    }
  },

  async getRefreshToken() {
    try {
      const credentials = await Keychain.getGenericPassword({
        service: REFRESH_TOKEN_SERVICE,
      });
      if (credentials) {
        return credentials.password;
      }
      return null;
    } catch (error) {
      console.error('Failed to retrieve refresh token:', error);
      return null;
    }
  },

  async clearAll() {
    try {
      await Keychain.resetGenericPassword({ service: AUTH_TOKEN_SERVICE });
      await Keychain.resetGenericPassword({ service: REFRESH_TOKEN_SERVICE });
    } catch (error) {
      console.error('Failed to clear secure storage:', error);
      throw error;
    }
  },
};

