import AsyncStorage from '@react-native-async-storage/async-storage';

// AsyncStorage is used ONLY for non-sensitive UI preferences.
// NEVER store tokens, passwords, or secrets here.

const UI_PREFS_KEY = '@ui_preferences';
const USER_DISPLAY_KEY = '@user_display_info';

export const UIStorage = {
  async saveUserDisplayInfo(displayInfo) {
    // Only store non-sensitive display data: name, avatar URL, theme preference
    // NEVER store email, phone, tokens, or any PII beyond display name
    const safeDisplayInfo = {
      displayName: displayInfo.displayName || '',
      avatarUrl: displayInfo.avatarUrl || '',
      preferredTheme: displayInfo.preferredTheme || 'light',
      lastActiveScreen: displayInfo.lastActiveScreen || 'Home',
    };
    try {
      await AsyncStorage.setItem(USER_DISPLAY_KEY, JSON.stringify(safeDisplayInfo));
    } catch (error) {
      console.error('Failed to save UI display info:', error);
    }
  },

  async getUserDisplayInfo() {
    try {
      const data = await AsyncStorage.getItem(USER_DISPLAY_KEY);
      return data ? JSON.parse(data) : null;
    } catch (error) {
      console.error('Failed to retrieve UI display info:', error);
      return null;
    }
  },

  async saveUIPreferences(prefs) {
    try {
      await AsyncStorage.setItem(UI_PREFS_KEY, JSON.stringify(prefs));
    } catch (error) {
      console.error('Failed to save UI preferences:', error);
    }
  },

  async getUIPreferences() {
    try {
      const data = await AsyncStorage.getItem(UI_PREFS_KEY);
      return data ? JSON.parse(data) : null;
    } catch (error) {
      console.error('Failed to retrieve UI preferences:', error);
      return null;
    }
  },

  async clearAll() {
    try {
      await AsyncStorage.multiRemove([UI_PREFS_KEY, USER_DISPLAY_KEY]);
    } catch (error) {
      console.error('Failed to clear UI storage:', error);
    }
  },
};

