import { SecureStorage } from './secureStorage';

const API_BASE_URL = 'https://api.myapp.com';

class ApiClient {
  async request(endpoint, options = {}) {
    const token = await SecureStorage.getAuthToken();

    const headers = {
      'Content-Type': 'application/json',
      ...(token && { Authorization: `Bearer ${token}` }),
      ...options.headers,
    };

    const config = {
      ...options,
      headers,
    };

    const response = await fetch(`${API_BASE_URL}${endpoint}`, config);

    if (response.status === 401) {
      const refreshed = await this.attemptTokenRefresh();
      if (refreshed) {
        const newToken = await SecureStorage.getAuthToken();
        headers.Authorization = `Bearer ${newToken}`;
        const retryResponse = await fetch(`${API_BASE_URL}${endpoint}`, {
          ...config,
          headers,
        });
        if (!retryResponse.ok) {
          throw new ApiError(retryResponse.status, await retryResponse.text());
        }
        return retryResponse.json();
      }
      throw new AuthenticationError('Session expired. Please log in again.');
    }

    if (!response.ok) {
      throw new ApiError(response.status, await response.text());
    }

    return response.json();
  }

  async attemptTokenRefresh() {
    try {
      const refreshToken = await SecureStorage.getRefreshToken();
      if (!refreshToken) {
        return false;
      }

      const response = await fetch(`${API_BASE_URL}/auth/refresh`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ refreshToken }),
      });

      if (!response.ok) {
        await SecureStorage.clearAll();
        return false;
      }

      const data = await response.json();
      await SecureStorage.saveAuthToken(data.accessToken);
      if (data.refreshToken) {
        await SecureStorage.saveRefreshToken(data.refreshToken);
      }
      return true;
    } catch (error) {
      console.error('Token refresh failed:', error);
      return false;
    }
  }

  async login(email, password) {
    const response = await fetch(`${API_BASE_URL}/auth/login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email, password }),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new AuthenticationError(
        errorData.message || 'Login failed. Please check your credentials.'
      );
    }

    return response.json();
  }

  async signup(userData) {
    const response = await fetch(`${API_BASE_URL}/auth/signup`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(userData),
    });

    if (!response.ok) {
      const errorData = await response.json().catch(() => ({}));
      throw new ApiError(response.status, errorData.message || 'Signup failed.');
    }

    return response.json();
  }

  async validateToken() {
    return this.request('/auth/validate', { method: 'GET' });
  }

  async getUserProfile() {
    return this.request('/user/profile', { method: 'GET' });
  }

  async logout() {
    try {
      const token = await SecureStorage.getAuthToken();
      if (token) {
        await fetch(`${API_BASE_URL}/auth/logout`, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            Authorization: `Bearer ${token}`,
          },
        });
      }
    } catch (error) {
      // Server-side logout is best-effort; we always clear local state
      console.warn('Server logout failed:', error);
    }
  }
}

class ApiError extends Error {
  constructor(status, message) {
    super(message);
    this.name = 'ApiError';
    this.status = status;
  }
}

class AuthenticationError extends Error {
  constructor(message) {
    super(message);
    this.name = 'AuthenticationError';
  }
}

export const apiClient = new ApiClient();
export { ApiError, AuthenticationError };

