import React, { createContext, useContext, useReducer, useEffect, useCallback, useMemo } from 'react';
import { SecureStorage } from '../services/secureStorage';
import { UIStorage } from '../services/uiStorage';
import { apiClient, AuthenticationError } from '../services/apiClient';

const AuthContext = createContext(null);

const AUTH_ACTIONS = {
  RESTORE_TOKEN: 'RESTORE_TOKEN',
  SIGN_IN: 'SIGN_IN',
  SIGN_OUT: 'SIGN_OUT',
  SET_LOADING: 'SET_LOADING',
  SET_ERROR: 'SET_ERROR',
  CLEAR_ERROR: 'CLEAR_ERROR',
  UPDATE_USER_DISPLAY: 'UPDATE_USER_DISPLAY',
};

const initialState = {
  isLoading: true,
  isSignedIn: false,
  userDisplayInfo: null,
  error: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case AUTH_ACTIONS.RESTORE_TOKEN:
      return {
        ...state,
        isLoading: false,
        isSignedIn: action.payload.isSignedIn,
        userDisplayInfo: action.payload.userDisplayInfo,
        error: null,
      };
    case AUTH_ACTIONS.SIGN_IN:
      return {
        ...state,
        isLoading: false,
        isSignedIn: true,
        userDisplayInfo: action.payload.userDisplayInfo,
        error: null,
      };
    case AUTH_ACTIONS.SIGN_OUT:
      return {
        ...state,
        isLoading: false,
        isSignedIn: false,
        userDisplayInfo: null,
        error: null,
      };
    case AUTH_ACTIONS.SET_LOADING:
      return {
        ...state,
        isLoading: action.payload,
      };
    case AUTH_ACTIONS.SET_ERROR:
      return {
        ...state,
        isLoading: false,
        error: action.payload,
      };
    case AUTH_ACTIONS.CLEAR_ERROR:
      return {
        ...state,
        error: null,
      };
    case AUTH_ACTIONS.UPDATE_USER_DISPLAY:
      return {
        ...state,
        userDisplayInfo: action.payload,
      };
    default:
      return state;
  }
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  // Bootstrap: check for existing valid session on app start
  useEffect(() => {
    async function bootstrapAuth() {
      try {
        const token = await SecureStorage.getAuthToken();

        if (!token) {
          dispatch({
            type: AUTH_ACTIONS.RESTORE_TOKEN,
            payload: { isSignedIn: false, userDisplayInfo: null },
          });
          return;
        }

        // Validate the token against the server — never trust a local flag alone
        try {
          const validationResult = await apiClient.validateToken();

          // Token is valid; load cached display info for instant UI
          const cachedDisplayInfo = await UIStorage.getUserDisplayInfo();

          const displayInfo = cachedDisplayInfo || {
            displayName: validationResult.user?.displayName || '',
            avatarUrl: validationResult.user?.avatarUrl || '',
          };

          dispatch({
            type: AUTH_ACTIONS.RESTORE_TOKEN,
            payload: { isSignedIn: true, userDisplayInfo: displayInfo },
          });
        } catch (validationError) {
          // Token invalid or expired — try refresh
          const refreshed = await apiClient.attemptTokenRefresh();
          if (refreshed) {
            const cachedDisplayInfo = await UIStorage.getUserDisplayInfo();
            dispatch({
              type: AUTH_ACTIONS.RESTORE_TOKEN,
              payload: { isSignedIn: true, userDisplayInfo: cachedDisplayInfo },
            });
          } else {
            // Cleanup stale credentials
            await SecureStorage.clearAll();
            await UIStorage.clearAll();
            dispatch({
              type: AUTH_ACTIONS.RESTORE_TOKEN,
              payload: { isSignedIn: false, userDisplayInfo: null },
            });
          }
        }
      } catch (error) {
        console.error('Auth bootstrap failed:', error);
        await SecureStorage.clearAll();
        await UIStorage.clearAll();
        dispatch({
          type: AUTH_ACTIONS.RESTORE_TOKEN,
          payload: { isSignedIn: false, userDisplayInfo: null },
        });
      }
    }

    bootstrapAuth();
  }, []);

  const signIn = useCallback(async (email, password) => {
    dispatch({ type: AUTH_ACTIONS.SET_LOADING, payload: true });
    dispatch({ type: AUTH_ACTIONS.CLEAR_ERROR });

    try {
      // Input validation
      if (!email || !email.trim()) {
        throw new AuthenticationError('Email is required.');
      }
      if (!password) {
        throw new AuthenticationError('Password is required.');
      }

      const response = await apiClient.login(email.trim().toLowerCase(), password);

      // Store tokens in secure keychain — NEVER in AsyncStorage
      await SecureStorage.saveAuthToken(response.accessToken);
      if (response.refreshToken) {
        await SecureStorage.saveRefreshToken(response.refreshToken);
      }

      // Store only non-sensitive display info in AsyncStorage
      const displayInfo = {
        displayName: response.user?.displayName || response.user?.name || '',
        avatarUrl: response.user?.avatarUrl || '',
        preferredTheme: 'light',
      };
      await UIStorage.saveUserDisplayInfo(displayInfo);

      dispatch({
        type: AUTH_ACTIONS.SIGN_IN,
        payload: { userDisplayInfo: displayInfo },
      });

      return { success: true };
    } catch (error) {
      const errorMessage =
        error instanceof AuthenticationError
          ? error.message
          : 'An unexpected error occurred. Please try again.';

      dispatch({ type: AUTH_ACTIONS.SET_ERROR, payload: errorMessage });
      return { success: false, error: errorMessage };
    }
  }, []);

  const signUp = useCallback(async (userData) => {
    dispatch({ type: AUTH_ACTIONS.SET_LOADING, payload: true });
    dispatch({ type: AUTH_ACTIONS.CLEAR_ERROR });

    try {
      if (!userData.email || !userData.email.trim()) {
        throw new AuthenticationError('Email is required.');
      }
      if (!userData.password || userData.password.length < 8) {
        throw new AuthenticationError('Password must be at least 8 characters.');
      }
      if (!userData.name || !userData.name.trim()) {
        throw new AuthenticationError('Name is required.');
      }

      const response = await apiClient.signup({
        email: userData.email.trim().toLowerCase(),
        password: userData.password,
        name: userData.name.trim(),
      });

      await SecureStorage.saveAuthToken(response.accessToken);
      if (response.refreshToken) {
        await SecureStorage.saveRefreshToken(response.refreshToken);
      }

      const displayInfo = {
        displayName: response.user?.displayName || userData.name.trim(),
        avatarUrl: response.user?.avatarUrl || '',
        preferredTheme: 'light',
      };
      await UIStorage.saveUserDisplayInfo(displayInfo);

      dispatch({
        type: AUTH_ACTIONS.SIGN_IN,
        payload: { userDisplayInfo: displayInfo },
      });

      return { success: true };
    } catch (error) {
      const errorMessage =
        error instanceof AuthenticationError
          ? error.message
          : 'Signup failed. Please try again.';

      dispatch({ type: AUTH_ACTIONS.SET_ERROR, payload: errorMessage });
      return { success: false, error: errorMessage };
    }
  }, []);

  const signOut = useCallback(async () => {
    dispatch({ type: AUTH_ACTIONS.SET_LOADING, payload: true });

    try {
      // Notify server (best-effort)
      await apiClient.logout();
    } catch (error) {
      console.warn('Server-side logout error:', error);
    } finally {
      // Always clear local secure storage and UI storage
      await SecureStorage.clearAll();
      await UIStorage.clearAll();
      dispatch({ type: AUTH_ACTIONS.SIGN_OUT });
    }
  }, []);

  const clearError = useCallback(() => {
    dispatch({ type: AUTH_ACTIONS.CLEAR_ERROR });
  }, []);

  const contextValue = useMemo(
    () => ({
      ...state,
      signIn,
      signUp,
      signOut,
      clearError,
    }),
    [state, signIn, signUp, signOut, clearError]
  );

  return <AuthContext.Provider value={contextValue}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

